const t=JSON.parse('{"key":"v-2ba84018","path":"/posts/%E6%B5%8B%E7%BB%98/%E7%A9%BA%E9%97%B4%E6%95%B0%E6%8D%AE%E5%88%86%E6%9E%90%E3%80%82.html","title":"空间数据分析。","lang":"en-US","frontmatter":{"description":"空间数据分析。 空间数据分析详解 1. 概述 空间数据分析 (Spatial Data Analysis) 是指对具有地理位置信息的数据进行分析，以揭示空间分布模式、空间关联关系以及空间变化趋势。它广泛应用于地理信息系统 (GIS)、遥感、环境科学、城市规划、交通管理等领域。 2. 空间数据类型 空间数据主要分为两类： 矢量数据 (Vector Data): 用点、线、面等几何要素表示空间对象，例如： 点：城市位置、气象站位置 线：道路、河流、边界 面：行政区划、土地利用类型 栅格数据 (Raster Data): 用规则网格表示空间现象，每个网格单元 (像素) 存储一个属性值，例如： 数字高程模型 (DEM) 遥感影像 气象数据","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/posts/%E6%B5%8B%E7%BB%98/%E7%A9%BA%E9%97%B4%E6%95%B0%E6%8D%AE%E5%88%86%E6%9E%90%E3%80%82.html"}],["meta",{"property":"og:site_name","content":"入川为王"}],["meta",{"property":"og:title","content":"空间数据分析。"}],["meta",{"property":"og:description","content":"空间数据分析。 空间数据分析详解 1. 概述 空间数据分析 (Spatial Data Analysis) 是指对具有地理位置信息的数据进行分析，以揭示空间分布模式、空间关联关系以及空间变化趋势。它广泛应用于地理信息系统 (GIS)、遥感、环境科学、城市规划、交通管理等领域。 2. 空间数据类型 空间数据主要分为两类： 矢量数据 (Vector Data): 用点、线、面等几何要素表示空间对象，例如： 点：城市位置、气象站位置 线：道路、河流、边界 面：行政区划、土地利用类型 栅格数据 (Raster Data): 用规则网格表示空间现象，每个网格单元 (像素) 存储一个属性值，例如： 数字高程模型 (DEM) 遥感影像 气象数据"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"og:updated_time","content":"2025-08-16T04:37:55.000Z"}],["meta",{"property":"article:author","content":"入川为王"}],["meta",{"property":"article:modified_time","content":"2025-08-16T04:37:55.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"空间数据分析。\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2025-08-16T04:37:55.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"入川为王\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"空间数据分析详解","slug":"空间数据分析详解","link":"#空间数据分析详解","children":[]}],"git":{"createdTime":1755319075000,"updatedTime":1755319075000,"contributors":[{"name":"TikTrack Developer","email":"user@example.com","commits":1}]},"readingTime":{"minutes":3.41,"words":1024},"filePathRelative":"posts/测绘/空间数据分析。.md","localizedDate":"August 16, 2025","excerpt":"<h1> 空间数据分析。</h1>\\n<h2> 空间数据分析详解</h2>\\n<p><strong>1. 概述</strong></p>\\n<p>空间数据分析 (Spatial Data Analysis) 是指对具有地理位置信息的数据进行分析，以揭示空间分布模式、空间关联关系以及空间变化趋势。它广泛应用于地理信息系统 (GIS)、遥感、环境科学、城市规划、交通管理等领域。</p>\\n<p><strong>2. 空间数据类型</strong></p>\\n<p>空间数据主要分为两类：</p>\\n<ul>\\n<li><strong>矢量数据 (Vector Data):</strong> 用点、线、面等几何要素表示空间对象，例如：\\n<ul>\\n<li>点：城市位置、气象站位置</li>\\n<li>线：道路、河流、边界</li>\\n<li>面：行政区划、土地利用类型</li>\\n</ul>\\n</li>\\n<li><strong>栅格数据 (Raster Data):</strong> 用规则网格表示空间现象，每个网格单元 (像素) 存储一个属性值，例如：\\n<ul>\\n<li>数字高程模型 (DEM)</li>\\n<li>遥感影像</li>\\n<li>气象数据</li>\\n</ul>\\n</li>\\n</ul>","autoDesc":true}');export{t as data};
